#include <iostream>
#include <thread>
#include <chrono>
#include <vector>
#include <string>

// --- Basic thread functions ---

void printMessage(const std::string& msg, int count) {
    for (int i = 0; i < count; i++) {
        std::cout << msg << " (" << i + 1 << ")" << std::endl;
        std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }
}

void longTask(int id, int duration) {
    std::cout << "Task " << id << " started (duration: " << duration << "s)" << std::endl;
    std::this_thread::sleep_for(std::chrono::seconds(duration));
    std::cout << "Task " << id << " finished" << std::endl;
}

// --- Function that returns a value (using reference) ---

void computeSum(int start, int end, int& result) {
    result = 0;
    for (int i = start; i <= end; i++) {
        result += i;
    }
    std::cout << "Sum from " << start << " to " << end << " = " << result << std::endl;
}

// --- Thread with lambda ---

void lambdaExample() {
    std::cout << "\n--- Lambda Thread ---" << std::endl;
    int counter = 0;

    std::thread t([&counter]() {
        for (int i = 0; i < 5; i++) {
            counter++;
            std::cout << "Counter: " << counter << std::endl;
            std::this_thread::sleep_for(std::chrono::milliseconds(50));
        }
    });

    t.join();
    std::cout << "Final counter: " << counter << std::endl;
}

int main() {
    std::cout << "=== Intro to Multithreading — std::thread ===" << std::endl;

    // 1. Basic thread
    std::cout << "\n--- Basic Thread ---" << std::endl;
    std::thread t1(printMessage, "Hello from thread", 3);

    // Main thread does something too
    for (int i = 0; i < 3; i++) {
        std::cout << "Main thread: " << i << std::endl;
        std::this_thread::sleep_for(std::chrono::milliseconds(50));
    }

    t1.join();

    // 2. Multiple threads
    std::cout << "\n--- Multiple Threads ---" << std::endl;
    std::thread t2(printMessage, "Thread A", 4);
    std::thread t3(printMessage, "Thread B", 3);

    t2.join();
    t3.join();

    // 3. Thread with return value (via reference)
    std::cout << "\n--- Thread with Return Value ---" << std::endl;
    int result;
    std::thread t4(computeSum, 1, 100, std::ref(result));
    t4.join();
    std::cout << "Final result: " << result << std::endl;

    // 4. Thread with lambda
    lambdaExample();

    // 5. Vector of threads
    std::cout << "\n--- Vector of Threads ---" << std::endl;
    std::vector<std::thread> threads;

    for (int i = 0; i < 5; i++) {
        threads.push_back(std::thread(longTask, i + 1, 1));
    }

    for (auto& t : threads) {
        t.join();
    }

    // 6. Thread ID
    std::cout << "\n--- Thread IDs ---" << std::endl;
    std::thread t5([]() {
        std::cout << "Thread ID: " << std::this_thread::get_id() << std::endl;
    });

    std::cout << "Main thread ID: " << std::this_thread::get_id() << std::endl;
    t5.join();

    // 7. Detaching a thread (use with caution!)
    std::cout << "\n--- Detached Thread ---" << std::endl;
    std::thread t6(printMessage, "Detached thread", 3);
    t6.detach();

    // Give detached thread time to run
    std::this_thread::sleep_for(std::chrono::milliseconds(500));

    std::cout << "\n--- Thread Safety Warning ---" << std::endl;
    std::cout << "⚠️ Threads share memory!" << std::endl;
    std::cout << "⚠️ Race conditions can occur!" << std::endl;
    std::cout << "⚠️ Use synchronization (next lesson)!" << std::endl;

    return 0;
}

