#include <iostream>
#include <thread>
#include <chrono>
#include <vector>
#include <string>

void countUp(const std::string& name, int max) {
    for (int i = 1; i <= max; i++) {
        std::cout << name << ": " << i << std::endl;
        std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }
}

int main() {
    std::cout << "=== Multithreading Demo ===" << std::endl;

    std::cout << "\n--- Two Threads ---" << std::endl;
    std::thread t1(countUp, "Thread A", 5);
    std::thread t2(countUp, "Thread B", 3);

    t1.join();
    t2.join();

    std::cout << "\n--- Lambda Thread ---" << std::endl;
    std::thread t3([]() {
        for (int i = 1; i <= 4; i++) {
            std::cout << "Lambda: " << i << std::endl;
            std::this_thread::sleep_for(std::chrono::milliseconds(100));
        }
    });
    t3.join();

    std::cout << "\n--- Vector of Threads ---" << std::endl;
    std::vector<std::thread> threads;
    for (int i = 0; i < 3; i++) {
        threads.push_back(std::thread(countUp, "Worker " + std::to_string(i + 1), 3));
    }

    for (auto& t : threads) {
        t.join();
    }

    std::cout << "\n✅ All threads completed!" << std::endl;

    return 0;
}
